import React, { useState, useEffect, useRef } from "react"
import { motion, AnimatePresence } from "framer-motion"

// Optimized Concept Assets (Base64) - 512px JPEGs
const CONCEPT_IMAGES = [
  "data:image/jpeg;base64,_placeholder_1",
  "data:image/jpeg;base64,_placeholder_2"
]

const logo = "data:image/png;base64,"

export const ConceptShowcase = ({ onEnterApp }) => {
  const [rotation, setRotation] = useState(0)
  const [products] = useState(() => CONCEPT_IMAGES.map((src, index) => ({
    id: `concept-${index}`,
    imageUrl: src,
    angle: index * (360 / (CONCEPT_IMAGES.length || 1)),
  })))

  useEffect(() => {
    let frameId
    const animate = () => {
      setRotation(prev => (prev + 0.25) % 360)
      frameId = requestAnimationFrame(animate)
    }
    animate()
    return () => cancelAnimationFrame(frameId)
  }, [])

  return (
    <div className="relative w-full min-h-screen bg-white overflow-hidden font-inter flex flex-col items-center justify-center">
      {/* 3D Carousel Container */}
      <div className="relative w-full h-[40vh] sm:h-[50vh] flex items-center justify-center">
        <div 
          className="relative w-full h-full"
          style={{
            perspective: "1200px",
            transformStyle: "preserve-3d"
          }}
        >
          <div 
            className="absolute inset-0 flex items-center justify-center"
            style={{
              transformStyle: "preserve-3d",
              transform: `rotateY(${rotation}deg)`
            }}
          >
            {products.map((p) => (
              <div
                key={p.id}
                className="absolute w-[260px] h-[390px] sm:w-[320px] sm:h-[480px]"
                style={{
                  transform: `rotateY(${p.angle}deg) translateZ(400px)`,
                  backfaceVisibility: "hidden"
                }}
              >
                <div className="w-full h-full rounded-[2.5rem] shadow-[0_30px_60px_rgba(0,0,0,0.15)] flex items-center justify-center overflow-hidden bg-white">
                  <img src={p.imageUrl} alt="Bottle" className="w-full h-full object-cover" />
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Text UI */}
      <div className="relative z-20 text-center px-6 mt-4">
        <div className="w-14 h-14 sm:w-16 sm:h-16 rounded-2xl shadow-sm overflow-hidden mb-6 ring-1 ring-zinc-100 flex items-center justify-center bg-white mx-auto">
          <img src={logo} alt="App Icon" className="w-10 h-10 sm:w-11 sm:h-11 object-cover" />
        </div>
        <h1 className="text-4xl sm:text-5xl font-outfit font-light uppercase tracking-[0.2em] text-zinc-900 mb-6">
          O ACERVO
        </h1>
        <p className="text-sm font-light text-zinc-500 max-w-xs mx-auto mb-4 leading-relaxed">
          Curadoria premium de bebidas exclusivas.
        </p>
        <button 
          onClick={onEnterApp}
          className="bg-zinc-900 text-white px-10 py-4 rounded-full text-xs font-bold tracking-widest hover:bg-black transition-all"
        >
          ENTRAR NO ACERVO →
        </button>
      </div>
    </div>
  )
}
